"use client";
import { FormEvent, useEffect, useMemo, useState } from "react";
import { Bell, Bookmark, CalendarDays, Camera, Cat, Check, ChevronDown, ChevronRight, Heart, Home, LogOut, MapPin, Menu, MessageCircle, Pencil, Plus, Search, ShieldCheck, SlidersHorizontal, Sparkles, Star, Trash2, X } from "lucide-react";
import { places, reviews, type Place } from "@/lib/data";
import { AuthModal, Onboarding, type DemoUser } from "@/components/functional-modals";
import { defaultCat, usePersistentState, type CatProfile, type Reminder, type UserReview } from "@/lib/use-persistent-state";
import { reviewNeedsModeration, validateCommunityContent } from "@/lib/content-filter";
import { createClient } from "@/lib/supabase";
import { deleteReminder as deleteReminderRemote, deleteReview as deleteReviewRemote, loadPrivateData, loadRecommendationSignals, saveCat as saveCatRemote, saveDemoFollow, saveReminder as saveReminderRemote, saveReview as saveReviewRemote, uploadCatPhoto } from "@/lib/supabase-repository";
import { calculateAge, missingProfileFields, profileCompletion, syncBirthdayReminder } from "@/lib/cat-profile";
import { buildSimilarCatRecommendations, type FollowSignal } from "@/lib/recommendations";
type Tab = "Inicio" | "Explorar" | "Mi gato" | "Agenda";
type Editor = "cat" | "reminder" | "review" | "compare" | null;
function Logo() { return <div className="logo"><span className="logo-mark"><Cat size={20}/></span><span>Miau<span>pedia</span></span></div>; }
function Stars({ rating }: {
    rating: number;
}) { return <span className="stars"><Star size={15} fill="currentColor"/><b>{rating.toFixed(1)}</b></span>; }
function Disclaimer() { return <div className="disclaimer"><ShieldCheck /><p><b>Información comunitaria, no asesoramiento médico.</b><br />Miaupedia no reemplaza la atención veterinaria ni proporciona diagnósticos, tratamientos o recomendaciones médicas.</p></div>; }
function LockedState({ onLogin }: {
    onLogin: () => void;
}) { return <div className="empty locked"><ShieldCheck /><h3>Tu espacio personal está protegido</h3><p>Inicia sesión para guardar y sincronizar esta información.</p><button onClick={onLogin}>Iniciar sesión</button></div>; }
function PlaceCard({ place, saved, onSave, onOpen, onCompare }: {
    place: Place;
    saved: boolean;
    onSave: () => void;
    onOpen: () => void;
    onCompare: () => void;
}) {
    return <article className="place-card" onClick={onOpen}><div className="place-image" style={{ backgroundImage: `url(${place.image})` }}>{place.sponsored && <span className="sponsored">Patrocinado</span>}<button className={`save ${saved ? "active" : ""}`} onClick={e => { e.stopPropagation(); onSave(); }} aria-label="Guardar"><Heart size={18} fill={saved ? "currentColor" : "none"}/></button></div><div className="place-copy"><div className="place-meta"><span>{place.category}</span><Stars rating={place.rating}/></div><h3>{place.name}</h3><p><MapPin size={14}/> {place.district} · {place.reviews} reseñas</p><div className="tags">{place.tags.map(t => <span key={t}>{t}</span>)}</div><div className="price-row"><strong>{place.price}</strong>{place.category === "Producto" ? <button className="compare-add" onClick={e => { e.stopPropagation(); onCompare(); }}>Comparar</button> : place.open && <span className="open">Abierto ahora</span>}</div></div></article>;
}
export function MiaupediaApp() {
    const [tab, setTab] = useState<Tab>("Inicio");
    const [query, setQuery] = useState("");
    const [category, setCategory] = useState("Todos");
    const [district, setDistrict] = useState("Todos");
    const [saved, setSaved] = usePersistentState<number[]>("miaupedia:follows", [1]);
    const [cats, setCats, hydrated] = usePersistentState<CatProfile[]>("miaupedia:cats", [defaultCat]);
    const [reminders, setReminders] = usePersistentState<Reminder[]>("miaupedia:reminders", [{ id: "r1", catId: "demo-luna", type: "Desparasitación", date: "2026-06-24", description: "Desparasitación programada", completed: false }, { id: "r2", catId: "demo-luna", type: "Vacuna", date: "2026-08-12", description: "Vacuna anual", completed: false }]);
    const [userReviews, setUserReviews] = usePersistentState<UserReview[]>("miaupedia:reviews", []);
    const [user, setUser] = usePersistentState<DemoUser | null>("miaupedia:user", null);
    const [onboarded, setOnboarded] = usePersistentState("miaupedia:onboarded", false);
    const [selected, setSelected] = useState<Place | null>(null);
    const [compare, setCompare] = useState<number[]>([]);
    const [showFilters, setShowFilters] = useState(false);
    const [notice, setNotice] = useState("");
    const [authOpen, setAuthOpen] = useState(false);
    const [showOnboarding, setShowOnboarding] = useState(false);
    const [editor, setEditor] = useState<Editor>(null);
    const [editingCat, setEditingCat] = useState<CatProfile | null>(null);
    const [editingReview, setEditingReview] = useState<UserReview | null>(null);
    const [mobileOpen, setMobileOpen] = useState(false);
    const [recommendationSignals, setRecommendationSignals] = useState<FollowSignal[]>([]);
    const primaryCat = cats[0];
    const flash = (m: string) => { setNotice(m); setTimeout(() => setNotice(""), 2500); };
    const requireUser = (fn: () => void) => user ? fn() : setAuthOpen(true);
    const results = useMemo(() => places.filter(p => (category === "Todos" || p.category === category) && (district === "Todos" || p.district === district) && `${p.name} ${p.category} ${p.district}`.toLowerCase().includes(query.toLowerCase())), [category, district, query]);
    useEffect(() => { const s = createClient(); if (!s)
        return; const apply = async (id: string) => { try {
        const remote = await loadPrivateData(id);
        if (remote) {
            setCats(remote.cats);
            setReminders(remote.reminders);
            setUserReviews(remote.userReviews);
            setSaved(remote.follows);
        }
        setRecommendationSignals(await loadRecommendationSignals());
    }
    catch {
        flash("Sesión iniciada; no se pudo sincronizar la base de datos");
    } }; s.auth.getUser().then(({ data }) => { if (data.user) {
        setUser({ id: data.user.id, email: data.user.email || "", name: data.user.user_metadata.display_name || "Miauamigo" });
        void apply(data.user.id);
    } }); const { data: l } = s.auth.onAuthStateChange((_e, session) => { if (session) {
        setUser({ id: session.user.id, email: session.user.email || "", name: session.user.user_metadata.display_name || "Miauamigo" });
        void apply(session.user.id);
    } }); return () => l.subscription.unsubscribe(); }, [setCats, setReminders, setSaved, setUser, setUserReviews]);
    const navigate = (next: Tab) => { setTab(next); setMobileOpen(false); window.scrollTo({ top: 0, behavior: "smooth" }); };
    const toggleSaved = (id: number) => requireUser(() => { const willFollow = !saved.includes(id); setSaved(v => willFollow ? [...v, id] : v.filter(x => x !== id)); if (user && createClient()) void saveDemoFollow(user.id, id, willFollow).catch(() => flash("Cambio guardado localmente; sincronización pendiente.")); flash(willFollow ? "Guardado en Favoritos" : "Eliminado de favoritos"); });
    const addCompare = (id: number) => { setCompare(v => v.includes(id) ? v.filter(x => x !== id) : v.length < 3 ? [...v, id] : v); if (compare.length >= 3 && !compare.includes(id))
        flash("Puedes comparar hasta 3 productos"); };
    const signOut = async () => { await createClient()?.auth.signOut(); setUser(null); flash("Sesión cerrada"); };
    const saveCatProfile = async (cat: CatProfile) => {
        setCats(editingCat ? cats.map(current => current.id === cat.id ? cat : current) : [...cats, cat]);
        setReminders(syncBirthdayReminder(cat, reminders));
        setEditor(null); setShowOnboarding(false); setTab("Mi gato");
        if (user && createClient()) {
            try {
                let uploadedPhoto = cat.photo;
                if (cat.photo?.startsWith("data:")) {
                    try { uploadedPhoto = await uploadCatPhoto(user.id, cat.id, cat.photo); }
                    catch { uploadedPhoto = cat.photo; }
                }
                const synchronizedCat = { ...cat, photo: uploadedPhoto };
                await saveCatRemote(user.id, synchronizedCat);
                setCats(current => current.map(item => item.id === synchronizedCat.id ? synchronizedCat : item));
                flash("Perfil actualizado correctamente.");
            }
            catch { flash("Perfil guardado en este dispositivo. Sincronización pendiente."); }
        } else flash("Perfil actualizado correctamente.");
    };
    const persistReview = async (review: UserReview, place: Place) => {
        const normalized = { ...review, placeId: place.id };
        setUserReviews(editingReview ? userReviews.map(current => current.id === normalized.id ? normalized : current) : [...userReviews, normalized]);
        setEditor(null); setSelected(place);
        if (user && createClient()) {
            try { await saveReviewRemote(user.id, normalized, { kind: "demo", id: place.id }); flash(editingReview ? "Reseña actualizada correctamente." : "Reseña publicada correctamente."); }
            catch { flash("Reseña guardada localmente; sincronización pendiente."); }
        } else flash(editingReview ? "Reseña actualizada correctamente." : "Reseña publicada correctamente.");
    };
    const removeReview = async (id: string) => { setUserReviews(userReviews.filter(review => review.id !== id)); if (createClient()) await deleteReviewRemote(id); };
    const removeReminder = async (id: string) => { setReminders(reminders.filter(reminder => reminder.id !== id)); if (createClient()) await deleteReminderRemote(id); flash("Recordatorio eliminado."); };
    useEffect(() => { if (!user || !createClient())
        return; cats.filter(c => c.id !== "demo-luna").forEach(c => void saveCatRemote(user.id, c).catch(() => undefined)); reminders.filter(r => r.catId !== "demo-luna").forEach(r => void saveReminderRemote(r).catch(() => undefined)); }, [cats, reminders, user]);
    if (!hydrated)
        return <div className="app-loading"><Logo /><span /></div>;
    return <div className="app-shell"><header className="topbar"><button className="brand-button" onClick={() => navigate("Inicio")}><Logo /></button><nav className={`desktop-nav ${mobileOpen ? "mobile-open" : ""}`}>{(["Inicio", "Explorar", "Mi gato", "Agenda"] as Tab[]).map(x => <button key={x} className={tab === x ? "active" : ""} onClick={() => navigate(x)}>{x}</button>)}</nav><div className="header-actions"><button className="icon-button" onClick={() => flash(user ? "No tienes alertas nuevas" : "Inicia sesión para ver tus alertas")} aria-label="Alertas"><Bell /><span className="dot"/></button>{user ? <div className="account-menu"><button className="profile-pill"><span>{user.name.slice(0, 2).toUpperCase()}</span><b>{user.name}</b><ChevronDown /></button><div><button onClick={() => setShowOnboarding(true)}><Sparkles />Repetir onboarding</button><button onClick={signOut}><LogOut />Cerrar sesión</button></div></div> : <button className="login-button" onClick={() => setAuthOpen(true)}>Ingresar</button>}<button className="mobile-menu" onClick={() => setMobileOpen(!mobileOpen)}>{mobileOpen ? <X /> : <Menu />}</button></div></header>

  <main>{tab === "Inicio" && user && cats.length ? <PersonalDashboard userName={user.name} cats={cats} reminders={reminders} saved={saved} userReviews={userReviews} onNavigate={navigate} onOpenPlace={setSelected} /> : tab === "Inicio" && <><section className="hero"><div className="hero-copy"><span className="eyebrow"><Sparkles /> La comunidad felina del Perú</span><h1>Mejores decisiones<br />para <em>tu gato.</em></h1><p>Descubre productos, servicios y veterinarias recomendadas por personas con gatos como el tuyo.</p><div className="search-box"><Search /><input value={query} onChange={e => setQuery(e.target.value)} onKeyDown={e => e.key === "Enter" && navigate("Explorar")} placeholder="¿Qué estás buscando para tu gato?"/><button onClick={() => navigate("Explorar")}>Buscar</button></div><div className="popular"><span>Popular:</span>{["Veterinarias", "Arena", "Alimento", "Hoteles felinos"].map(x => <button key={x} onClick={() => { setQuery(x); navigate("Explorar"); }}>{x}</button>)}</div></div><div className="hero-visual"><div className="cat-photo"/><div className="floating-card score"><span><ShieldCheck /></span><div><b>4.9 de 5</b><small>Opiniones verificadas</small></div></div><div className="floating-card people"><div className="faces"><i>AM</i><i>JR</i><i>LC</i></div><div><b>+12 mil</b><small>cat lovers en Perú</small></div></div></div></section><div className="content-width home-disclaimer"><Disclaimer /></div>
    <section className="quick-section content-width"><div className="section-heading"><div><span className="kicker">EXPLORA MIAUPEDIA</span><h2>Todo lo que tu gato necesita</h2></div><button onClick={() => navigate("Explorar")}>Ver todo <ChevronRight /></button></div><div className="category-grid">{[["Veterinaria", "Especialistas cerca de ti", "🏥", "lilac"], ["Pet Shop", "Todo para consentirlo", "🛍️", "mint"], ["Producto", "Probados por la comunidad", "📦", "peach"], ["Hotel felino", "Un segundo hogar", "🏡", "blue"], ["Cuidador", "Personas de confianza", "🤝", "yellow"]].map(([a, b, c, d]) => <button className="category-card" key={a} onClick={() => { setCategory(a); navigate("Explorar"); }}><span className={d}>{c}</span><div><b>{a}</b><small>{b}</small></div><ChevronRight /></button>)}</div></section>
    <section className="recommend-section"><div className="content-width"><div className="section-heading"><div><span className="kicker">RECOMENDADOS PARA TI</span><h2>Los favoritos de la comunidad</h2></div><button onClick={() => navigate("Explorar")}>Explorar todos <ChevronRight /></button></div><div className="card-grid">{places.slice(0, 3).map(p => <PlaceCard key={p.id} place={p} saved={saved.includes(p.id)} onSave={() => toggleSaved(p.id)} onOpen={() => setSelected(p)} onCompare={() => addCompare(p.id)}/>)}</div></div></section>
    <section className="trust-band"><div className="content-width"><div><span className="trust-icon"><ShieldCheck /></span><div><h2>Experiencias reales.<br />Decisiones con confianza.</h2><p>La comunidad destaca las voces más útiles, no el contenido patrocinado.</p></div></div><div className="trust-stats"><span><b>12K+</b><small>Miembros</small></span><span><b>8.5K</b><small>Reseñas</small></span><span><b>1.2K</b><small>Opciones</small></span></div></div></section></>}

  {tab === "Explorar" && <section className="page content-width"><div className="page-title"><span className="kicker">DIRECTORIO FELINO</span><h1>Encuentra lo mejor para tu gato</h1><p>Opiniones reales de la comunidad peruana.</p></div><Disclaimer /><SafetyNotice /><CatalogSuggestions /><div className="explore-search"><Search /><input value={query} onChange={e => setQuery(e.target.value)} placeholder="Busca por nombre, categoría o distrito"/><button onClick={() => setShowFilters(!showFilters)}><SlidersHorizontal />Filtros</button></div>{showFilters && <div className="filter-panel"><label>Distrito<select value={district} onChange={e => setDistrict(e.target.value)}><option>Todos</option><option>Miraflores</option><option>Surco</option><option>San Borja</option><option>Barranco</option></select></label><label>Categoría<select value={category} onChange={e => setCategory(e.target.value)}><option>Todos</option><option>Veterinaria</option><option>Pet Shop</option><option>Hotel felino</option><option>Cuidador</option><option>Producto</option></select></label><label>Ubicación<input disabled value="Lima, Perú"/></label></div>}<div className="chips">{["Todos", "Veterinaria", "Pet Shop", "Producto", "Hotel felino", "Cuidador"].map(c => <button key={c} className={category === c ? "active" : ""} onClick={() => setCategory(c)}>{c}</button>)}</div><div className="result-line"><b>{results.length} resultados</b><span>Ordenar: mejor valorados <ChevronDown /></span></div><div className="card-grid explore-grid">{results.map(p => <PlaceCard key={p.id} place={p} saved={saved.includes(p.id)} onSave={() => toggleSaved(p.id)} onOpen={() => setSelected(p)} onCompare={() => addCompare(p.id)}/>)}</div>{!results.length && <div className="empty"><Search /><h3>No encontramos coincidencias</h3><p>Prueba otra búsqueda o limpia los filtros.</p><button onClick={() => { setQuery(""); setCategory("Todos"); setDistrict("Todos"); }}>Limpiar filtros</button></div>}{compare.length > 0 && <div className="compare-bar"><div><b>{compare.length} producto{compare.length > 1 ? "s" : ""}</b><small>Seleccionados para comparar</small></div><div className="mini-products">{compare.map(id => <span key={id} style={{ backgroundImage: `url(${places.find(p => p.id === id)?.image})` }}><button onClick={() => addCompare(id)}><X /></button></span>)}</div><button onClick={() => setEditor("compare")}>Comparar ahora</button></div>}</section>}

  {tab === "Mi gato" && <section className="page content-width"><div className="page-title row-title"><div><span className="kicker">MI FAMILIA FELINA</span><h1>Mis gatos</h1><p>Perfiles que personalizan tus descubrimientos.</p></div><button className="primary" onClick={() => requireUser(() => { setEditingCat(null); setEditor("cat"); })}><Plus />Añadir gato</button></div>{!user ? <LockedState onLogin={() => setAuthOpen(true)}/> : !cats.length ? <div className="empty"><Cat /><h3>Aún no has registrado ningún gato.</h3><p>Añade su perfil para personalizar tu experiencia.</p><button onClick={() => setEditor("cat")}>Añadir gato</button></div> : <><div className="cat-tabs">{cats.map(c => <button className={c.id === primaryCat.id ? "active" : ""} key={c.id}>{c.name}</button>)}</div><div className="cat-profile"><div className="cat-avatar" style={{ backgroundImage: `url(${primaryCat.photo || "https://images.unsplash.com/photo-1573865526739-10659fec78a5?auto=format&fit=crop&w=700&q=80"})` }}/><div className="cat-info"><div><span>Perfil completo {profileCompletion(primaryCat)}%</span><h2>{primaryCat.name}</h2><p>{primaryCat.breed} · {primaryCat.sex} · {calculateAge(primaryCat.birthDate).label}</p></div><div className="inline-actions"><button onClick={() => { setEditingCat(primaryCat); setEditor("cat"); }}><Pencil />Editar</button><button className="danger" onClick={() => confirm(`¿Eliminar el perfil de ${primaryCat.name}?`) && setCats(cats.filter(c => c.id !== primaryCat.id))}><Trash2 /></button></div><div className="profile-progress"><i style={{ width: `${profileCompletion(primaryCat)}%` }}/></div><div className="cat-stats"><span><b>{primaryCat.weight || "—"} kg</b><small>Peso</small></span><span><b>{primaryCat.sterilized ? "Sí" : "No"}</b><small>Esterilizado</small></span><span><b>{saved.length}</b><small>Seguidos</small></span></div></div></div><ProfileCompletion cat={primaryCat} onComplete={() => { setEditingCat(primaryCat); setEditor("cat"); }} /><CatReportActions cat={primaryCat} reminders={reminders.filter(r => r.catId === primaryCat.id)} /><UpcomingEvents reminders={reminders.filter(r => r.catId === primaryCat.id)} /><Disclaimer /><div className="profile-columns"><div className="panel"><div className="panel-head"><h3>Sus preferencias</h3><button onClick={() => { setEditingCat(primaryCat); setEditor("cat"); }}>Editar</button></div>{[["🍗", "Alimentos", primaryCat.food], ["✨", "Arenas", primaryCat.litter], ["🧶", "Juguetes", primaryCat.toys]].map(([icon, label, values]) => <div className="preference" key={String(label)}><span>{String(icon)}</span><div><small>{String(label)}</small><b>{(values as string[]).join(", ") || "Sin preferencias"}</b></div></div>)}</div><SimilarCatsPanel cat={primaryCat} /></div></>}</section>}

  {tab === "Agenda" && <section className="page content-width"><div className="page-title row-title"><div><span className="kicker">CUIDADOS AL DÍA</span><h1>Agenda{primaryCat ? ` de ${primaryCat.name}` : ""}</h1><p>Recordatorios sencillos para que nada se te pase.</p></div><button className="primary" onClick={() => requireUser(() => setEditor("reminder"))}><Plus />Nuevo recordatorio</button></div>{!user ? <LockedState onLogin={() => setAuthOpen(true)}/> : !reminders.length ? <div className="empty"><CalendarDays /><h3>No tienes recordatorios todavía</h3><p>Añade cumpleaños, vacunas o desparasitaciones.</p><button onClick={() => setEditor("reminder")}>Crear recordatorio</button></div> : <div className="agenda-layout"><div className="agenda-main"><h3>Próximos</h3>{[...reminders].sort((a, b) => a.date.localeCompare(b.date)).map(r => { const d = new Date(`${r.date}T12:00:00`); return <div className={`event ${r.completed ? "completed" : ""}`} key={r.id}><div className={`date ${r.type === "Vacuna" ? "violet" : r.type === "Cumpleaños" ? "peach" : ""}`}><b>{String(d.getDate()).padStart(2, "0")}</b><small>{d.toLocaleDateString("es-PE", { month: "short" }).toUpperCase()}</small></div><div><b>{r.description}</b><span>{r.type} · {cats.find(c => c.id === r.catId)?.name || "Mi gato"}</span></div><button className="event-done" onClick={() => setReminders(reminders.map(x => x.id === r.id ? { ...x, completed: !x.completed } : x))}>{r.completed ? "Reabrir" : "Completar"}</button><button className="event-delete" onClick={() => confirm("¿Eliminar este recordatorio?") && setReminders(reminders.filter(x => x.id !== r.id))}><Trash2 /></button></div>; })}</div><aside className="panel calendar-panel"><div className="panel-head"><h3>Resumen</h3><span>{reminders.filter(r => !r.completed).length} pendientes</span></div><div className="agenda-summary"><CalendarDays /><b>{reminders.filter(r => !r.completed).length}</b><p>recordatorios activos</p></div></aside></div>}<Disclaimer /></section>}</main>

  <footer><div className="content-width"><Logo /><p>Miaupedia es una plataforma de información y experiencias compartidas por la comunidad. No reemplaza la atención veterinaria profesional ni proporciona diagnósticos, tratamientos o recomendaciones médicas.</p><span>Hecho para los gatos del Perú 🇵🇪</span></div></footer><nav className="bottom-nav">{[["Inicio", Home], ["Explorar", Search], ["Mi gato", Cat], ["Agenda", CalendarDays]].map(([name, Icon]) => { const I = Icon as typeof Home; return <button key={String(name)} className={tab === name ? "active" : ""} onClick={() => navigate(name as Tab)}><I /><span>{String(name)}</span></button>; })}<button onClick={() => flash("No tienes alertas nuevas")}><Bell /><span>Alertas</span></button></nav>

  {selected && <DetailModal place={selected} saved={saved.includes(selected.id)} ownReviews={userReviews.filter(r => r.placeId === selected.id)} onClose={() => setSelected(null)} onSave={() => toggleSaved(selected.id)} onContact={() => requireUser(() => { setUserReviews(userReviews.map(r => r.placeId === selected.id ? { ...r, status: "En conversaci\u00f3n" } : r)); flash("Conversaci\u00f3n privada solicitada; la rese\u00f1a sigue visible"); })} onNewReview={() => requireUser(() => { const existing = userReviews.find(r => r.placeId === selected.id); setEditingReview(existing || null); setEditor("review"); })} onEdit={r => { setEditingReview(r); setEditor("review"); }} onDelete={id => void removeReview(id)} onReact={(id, key) => setUserReviews(userReviews.map(r => r.id === id ? { ...r, [key]: r[key] + 1 } : r))} onReport={id => setUserReviews(userReviews.map(r => r.id === id ? { ...r, reported: true, status: "En revisión" } : r))} onBusinessResponse={(id, response) => setUserReviews(userReviews.map(r => r.id === id ? { ...r, businessResponse: response } : r))}/>} 
  {authOpen && <AuthModal onClose={() => setAuthOpen(false)} onAuthenticated={u => { setUser(u); setAuthOpen(false); if (!onboarded)
        setShowOnboarding(true); }}/>}{showOnboarding && <Onboarding onSkip={() => { setOnboarded(true); setShowOnboarding(false); }} onFinish={(cat, interests) => { if (cat) { setCats([cat, ...cats.filter(c => c.id !== "demo-luna")]); setReminders(syncBirthdayReminder(cat, reminders)); } setSaved(Array.from(new Set([...saved, ...interests]))); setOnboarded(true); setShowOnboarding(false); flash("Tu perfil quedó listo"); }}/>}
  {editor === "cat" && <CatEditor initial={editingCat} onClose={() => setEditor(null)} onSave={cat => void saveCatProfile(cat)}/>}{editor === "reminder" && <ReminderEditor cats={cats} onClose={() => setEditor(null)} onSave={r => { setReminders([...reminders, r]); setEditor(null); flash("Recordatorio creado"); }}/>}{editor === "review" && selected && <ReviewEditor initial={editingReview} onClose={() => setEditor(null)} onSave={review => void persistReview(review, selected)}/>}{editor === "compare" && <CompareModal ids={compare} onClose={() => setEditor(null)}/>} {notice && <div className="toast"><Check />{notice}</div>}</div>;
}
function FormShell({ title, onClose, children }: {
    title: string;
    onClose: () => void;
    children: React.ReactNode;
}) { return <div className="modal-backdrop" onMouseDown={e => e.target === e.currentTarget && onClose()}><div className="form-modal"><button className="close" onClick={onClose}><X /></button><h2>{title}</h2>{children}</div></div>; }

function ProfileCompletion({ cat, onComplete }: { cat: CatProfile; onComplete: () => void }) {
    const missing = missingProfileFields(cat), percentage = profileCompletion(cat);
    return <div className={`completion-card ${missing.length ? "incomplete" : "complete"}`}><div><b>Perfil completado: {percentage}%</b><div className="profile-progress"><i style={{ width: `${percentage}%` }}/></div>{missing.length ? <div className="missing-fields"><p>Falta completar:</p>{missing.map(field => <span key={field}>□ {field}</span>)}</div> : <p>La información principal está completa.</p>}</div>{missing.length > 0 && <button onClick={onComplete}>Completar perfil</button>}</div>;
}

function UpcomingEvents({ reminders }: { reminders: Reminder[] }) {
    const upcoming = [...reminders].filter(r => !r.completed).sort((a, b) => a.date.localeCompare(b.date)).slice(0, 3);
    return <section className="cat-upcoming"><div className="panel-head"><h3>Próximos eventos</h3><span>{upcoming.length} próximos</span></div>{upcoming.length ? upcoming.map(r => <div key={r.id}><CalendarDays /><span><b>{r.description}</b><small>{new Date(`${r.date}T12:00:00`).toLocaleDateString("es-PE", { day: "2-digit", month: "long", year: "numeric" })}</small></span></div>) : <p>No hay eventos próximos en la agenda.</p>}</section>;
}

function PersonalDashboard({ userName, cats, reminders, saved, userReviews, onNavigate, onOpenPlace }: { userName: string; cats: CatProfile[]; reminders: Reminder[]; saved: number[]; userReviews: UserReview[]; onNavigate: (tab: Tab) => void; onOpenPlace: (place: Place) => void }) {
    const primary = cats[0]; const upcoming = [...reminders].filter(item => !item.completed).sort((a, b) => a.date.localeCompare(b.date)).slice(0, 3); const followed = saved.map(id => places.find(place => place.id === id)).filter((place): place is Place => Boolean(place));
    return <section className="personal-dashboard content-width"><div className="dashboard-welcome"><div><span className="kicker">TU MIAUPEDIA</span><h1>Hola, {userName}</h1><p>Esto es lo más importante para tus gatos hoy.</p></div><button onClick={() => onNavigate("Explorar")}><Search />Explorar Miaupedia</button></div><div className="dashboard-grid"><section className="dashboard-panel dashboard-cats"><div className="panel-head"><h2>Mis gatos</h2><button onClick={() => onNavigate("Mi gato")}>Ver perfiles</button></div>{cats.map(cat => <button key={cat.id} onClick={() => onNavigate("Mi gato")}><span style={{ backgroundImage: `url(${cat.photo || "https://images.unsplash.com/photo-1573865526739-10659fec78a5?auto=format&fit=crop&w=300&q=70"})` }}/><div><b>{cat.name}</b><small>{calculateAge(cat.birthDate).label} · {cat.lifestyle}</small><i>{profileCompletion(cat)}% completo</i></div><ChevronRight /></button>)}</section><section className="dashboard-panel"><div className="panel-head"><h2>Próximos eventos</h2><button onClick={() => onNavigate("Agenda")}>Abrir agenda</button></div>{upcoming.length ? upcoming.map(item => <div className="dashboard-event" key={item.id}><CalendarDays /><div><b>{item.description}</b><small>{new Date(`${item.date}T12:00:00`).toLocaleDateString("es-PE", { day: "2-digit", month: "long" })} · {cats.find(cat => cat.id === item.catId)?.name}</small></div></div>) : <p className="dashboard-empty">No tienes eventos próximos.</p>}</section><section className="dashboard-panel"><div className="panel-head"><h2>Mis seguimientos</h2><button onClick={() => onNavigate("Explorar")}>Descubrir más</button></div>{followed.length ? followed.slice(0, 3).map(place => <button className="dashboard-follow" key={place.id} onClick={() => onOpenPlace(place)}><span style={{ backgroundImage: `url(${place.image})` }}/><div><b>{place.name}</b><small>{place.category} · {place.district}</small></div><Stars rating={place.rating}/></button>) : <p className="dashboard-empty">Aún no sigues productos ni negocios.</p>}</section><section className="dashboard-panel"><div className="panel-head"><h2>Mis reseñas</h2><b>{userReviews.length}</b></div>{userReviews.length ? userReviews.slice(0, 3).map(review => <div className="dashboard-review" key={review.id}><Stars rating={review.rating}/><p>{review.comment}</p><small>{review.status}{review.updatedAt ? ` · Editada ${new Date(review.updatedAt).toLocaleDateString("es-PE")}` : ""}</small></div>) : <p className="dashboard-empty">Tus experiencias publicadas aparecerán aquí.</p>}</section></div><div className="dashboard-lower"><SimilarCatsPanel cat={primary} /><section className="dashboard-panel recent-activity"><div className="panel-head"><h2>Actividad reciente</h2></div><p><Check /> Perfil de {primary.name}: {profileCompletion(primary)}% completo</p><p><Heart /> {saved.length} seguimiento{saved.length === 1 ? "" : "s"} activo{saved.length === 1 ? "" : "s"}</p><p><MessageCircle /> {userReviews.length} reseña{userReviews.length === 1 ? "" : "s"} publicada{userReviews.length === 1 ? "" : "s"}</p></section></div></section>;
}

function SimilarCatsPanel({ cat, signals = [] }: { cat: CatProfile; signals?: FollowSignal[] }) {
    const [remoteSignals, setRemoteSignals] = useState<FollowSignal[]>(signals);
    useEffect(() => { if (!signals.length) void loadRecommendationSignals().then(setRemoteSignals); }, [signals]);
    const results = buildSimilarCatRecommendations(cat, signals.length ? signals : remoteSignals); const recommendations = results.map(result => ({ result, place: places.find(place => place.id === result.listingId) })).filter((item): item is { result: typeof results[number]; place: Place } => Boolean(item.place));
    return <div className="panel similar-cats-panel"><div className="panel-head"><h3>Recomendaciones basadas en gatos similares</h3></div><p className="panel-intro">Coincidencias por raza, edad, esterilización, tipo de vida y preferencias registradas.</p>{recommendations.length ? recommendations.map(({ place, result }) => <div className="similar-recommendation" key={place.id}><span style={{ backgroundImage: `url(${place.image})` }}/><div><small>{place.category}</small><b>{place.name}</b><p>¿Por qué se recomienda?</p><ul><li>{result.similarCats} gatos similares utilizan esta opción.</li><li>{place.rating.toFixed(1)} estrellas.</li><li>{result.repurchaseRate}% volvería a elegirla.</li></ul></div></div>) : <div className="recommendation-empty"><Cat /><div><b>Aún no hay suficientes datos para generar recomendaciones personalizadas.</b><p>Cuando existan al menos tres coincidencias reales, aparecerán aquí. No mostramos sugerencias genéricas como si fueran personalizadas.</p></div></div>}</div>;
}

function CatReportActions({ cat, reminders }: { cat: CatProfile; reminders: Reminder[] }) {
    function exportReport(full: boolean) {
        const popup = window.open("", "_blank"); if (!popup) return; popup.opener = null;
        const safe = (value: unknown) => String(value || "—").replace(/[&<>"']/g, m => ({ "&": "&amp;", "<": "&lt;", ">": "&gt;", '"': "&quot;", "'": "&#039;" })[m] || m);
        const eventRows = reminders.length ? reminders.map(r => `<tr><td>${safe(r.type)}</td><td>${safe(new Date(`${r.date}T12:00:00`).toLocaleDateString("es-PE"))}</td><td>${safe(r.description)}</td></tr>`).join("") : '<tr><td colspan="3">Sin eventos registrados</td></tr>';
        popup.document.write(`<!doctype html><html lang="es"><head><title>Informe de ${safe(cat.name)}</title><style>@page{size:A4;margin:18mm}body{font:14px Arial;color:#18372e;line-height:1.5}header{display:flex;justify-content:space-between;border-bottom:3px solid #176b52;padding-bottom:18px}h1,h2{margin:0 0 10px}h2{font-size:17px;margin-top:24px}.badge{background:#e5f0eb;color:#176b52;padding:6px 10px;border-radius:20px}.grid{display:grid;grid-template-columns:1fr 1fr;gap:8px 30px}.photo{width:105px;height:105px;object-fit:cover;border-radius:16px}table{width:100%;border-collapse:collapse}td,th{padding:8px;border-bottom:1px solid #ddd;text-align:left}footer{margin-top:28px;padding-top:12px;border-top:1px solid #ddd;color:#68736e;font-size:10px}.notice{background:#f7f5ef;padding:12px;border-radius:8px}</style></head><body><header><div><span class="badge">Miaupedia · Informe ${full ? "completo" : "corto"}</span><h1>${safe(cat.name)}</h1><p>Generado el ${new Date().toLocaleDateString("es-PE")}</p></div>${cat.photo ? `<img class="photo" src="${safe(cat.photo)}">` : ""}</header><h2>Datos generales</h2><div class="grid"><span><b>Edad:</b> ${safe(calculateAge(cat.birthDate).label)}</span><span><b>Sexo:</b> ${safe(cat.sex)}</span><span><b>Raza:</b> ${safe(cat.breed)}</span><span><b>Tipo de vida:</b> ${safe(cat.lifestyle)}</span><span><b>Peso:</b> ${cat.weight ? `${safe(cat.weight)} kg` : "—"}</span><span><b>Fecha del peso:</b> ${cat.weightDate ? new Date(`${cat.weightDate}T12:00:00`).toLocaleDateString("es-PE") : "—"}</span></div><h2>Preferencias</h2><p><b>Alimentos:</b> ${safe(cat.food.join(", "))}<br><b>Arenas:</b> ${safe(cat.litter.join(", "))}<br><b>Juguetes:</b> ${safe(cat.toys.join(", "))}</p>${full ? `<h2>Agenda</h2><table><thead><tr><th>Tipo</th><th>Fecha</th><th>Descripción</th></tr></thead><tbody>${eventRows}</tbody></table><h2>Información adicional</h2><p><b>Veterinaria habitual:</b> ${safe(cat.regularVet)}<br><b>Personalidad:</b> ${safe(cat.personality)}<br><b>Observaciones:</b> ${safe(cat.ownerNotes)}</p>` : ""}<p class="notice">Este documento organiza información aportada por el dueño. No es una historia clínica ni reemplaza la atención veterinaria.</p><footer>Miaupedia · Comunidad de experiencias sobre gatos en Perú</footer><script>window.onload=()=>setTimeout(()=>window.print(),300)</script></body></html>`);
        popup.document.close();
    }
    return <div className="report-actions"><div><b>Informe ejecutivo de {cat.name}</b><small>Versión lista para guardar como PDF o imprimir.</small></div><button onClick={() => exportReport(false)}>PDF corto</button><button className="primary" onClick={() => exportReport(true)}>PDF completo</button></div>;
}

function SafetyNotice() {
    const [reporting, setReporting] = useState(false); const [sent, setSent] = useState(false);
    return <div className="safety-card"><ShieldCheck /><div><b>Protege tu cuenta y tu dinero</b><p>No envíes dinero, datos bancarios ni códigos de verificación. Reporta comportamientos sospechosos.</p></div><button onClick={() => setReporting(true)}>🚩 Reportar usuario</button>{reporting && <div className="safety-report"><button className="close" onClick={() => setReporting(false)}><X /></button><b>Motivo del reporte</b><select aria-label="Motivo"><option>Spam</option><option>Estafa</option><option>Acoso</option><option>Suplantación</option><option>Otro</option></select><button className="primary" onClick={() => { setSent(true); setReporting(false); }}>Enviar para revisión</button></div>}{sent && <small>Reporte enviado a revisión. El contenido no se elimina automáticamente.</small>}</div>;
}

function CatalogSuggestions() {
    const [suggestions, setSuggestions] = usePersistentState<{ id: string; type: string; name: string; district: string; status: string }[]>("miaupedia:suggestions", []); const [open, setOpen] = useState(false);
    function submit(e: FormEvent<HTMLFormElement>) { e.preventDefault(); const f = new FormData(e.currentTarget); setSuggestions([...suggestions, { id: crypto.randomUUID(), type: String(f.get("type")), name: String(f.get("name")), district: String(f.get("district")), status: "En revisión" }]); setOpen(false); }
    return <div className="catalog-suggestion"><div><b>¿Falta algo en Miaupedia?</b><p>Ayúdanos a mejorar el catálogo. Todas las sugerencias pasan por moderación.</p></div><button onClick={() => setOpen(true)}>Sugerir al catálogo</button>{suggestions.length > 0 && <span>{suggestions.length} sugerencia{suggestions.length > 1 ? "s" : ""} en revisión</span>}{open && <div className="modal-backdrop"><form className="form-modal stack-form" onSubmit={submit}><button type="button" className="close" onClick={() => setOpen(false)}><X /></button><h2>Nueva sugerencia</h2><label>Tipo<select name="type"><option>Producto</option><option>Veterinaria</option><option>Negocio</option></select></label><label>Nombre<input name="name" required/></label><label>Distrito<input name="district" required/></label><button className="primary full">Enviar a moderación</button></form></div>}</div>;
}

function BusinessDashboard({ reviews: items, onRespond }: { reviews: UserReview[]; onRespond: (id: string, response: string) => void }) {
    const [replying, setReplying] = useState<string | null>(null); const total = items.length; const average = total ? items.reduce((sum, item) => sum + item.rating, 0) / total : 0;
    return <section className="business-dashboard"><div className="panel-head"><div><span className="verified-label"><ShieldCheck /> Negocio verificado</span><h3>Panel de reseñas</h3></div><small>Los negocios pueden responder, pero no borrar, modificar u ocultar reseñas.</small></div><div className="business-metrics">{[["Total reseñas", total], ["Promedio", average.toFixed(1)], ["Nuevas", items.filter(r => r.status === "Publicada").length], ["Pendientes", items.filter(r => r.status === "En revisión").length], ["Respondidas", items.filter(r => r.businessResponse).length]].map(([label, value]) => <span key={String(label)}><b>{value}</b><small>{label}</small></span>)}</div>{items.map(item => <div className="business-review-row" key={item.id}><span>{item.comment.slice(0, 65)}{item.comment.length > 65 ? "…" : ""}</span>{item.businessResponse ? <small>Respuesta publicada</small> : <button onClick={() => setReplying(item.id)}>Responder públicamente</button>}{replying === item.id && <form onSubmit={e => { e.preventDefault(); const response = String(new FormData(e.currentTarget).get("response")); onRespond(item.id, response); setReplying(null); }}><textarea name="response" required placeholder="Respuesta respetuosa del negocio"/><button className="primary">Publicar respuesta</button></form>}</div>)}</section>;
}
function CatEditor({ initial, onClose, onSave }: {
    initial: CatProfile | null;
    onClose: () => void;
    onSave: (c: CatProfile) => void;
}) {
    const [photo, setPhoto] = useState(initial?.photo || ""); const [photoError, setPhotoError] = useState("");
    function choosePhoto(file?: File) {
        if (!file) return; if (!file.type.startsWith("image/")) { setPhotoError("Selecciona una imagen válida."); return; }
        if (file.size > 8 * 1024 * 1024) { setPhotoError("La imagen debe pesar menos de 8 MB."); return; }
        const reader = new FileReader(); reader.onload = () => { const image = new Image(); image.onload = () => { const scale = Math.min(1, 900 / Math.max(image.width, image.height)); const canvas = document.createElement("canvas"); canvas.width = Math.round(image.width * scale); canvas.height = Math.round(image.height * scale); canvas.getContext("2d")?.drawImage(image, 0, 0, canvas.width, canvas.height); setPhoto(canvas.toDataURL("image/jpeg", .82)); setPhotoError(""); }; image.src = String(reader.result); }; reader.readAsDataURL(file);
    }
    function submit(e: FormEvent<HTMLFormElement>) {
        e.preventDefault(); const f = new FormData(e.currentTarget);
        onSave({ id: initial?.id || crypto.randomUUID(), name: String(f.get("name")), sex: String(f.get("sex")) as CatProfile["sex"], breed: String(f.get("breed")), sterilized: f.get("sterilized") === "on", birthDate: String(f.get("birthDate")), weight: Number(f.get("weight")), weightDate: String(f.get("weightDate")), photo, lifestyle: String(f.get("lifestyle")) as CatProfile["lifestyle"], personality: String(f.get("personality")), regularVet: String(f.get("regularVet")), ownerNotes: String(f.get("ownerNotes")), food: String(f.get("food")).split(",").map(x => x.trim()).filter(Boolean), litter: String(f.get("litter")).split(",").map(x => x.trim()).filter(Boolean), toys: String(f.get("toys")).split(",").map(x => x.trim()).filter(Boolean) });
    }
    return <FormShell title={initial ? "Editar perfil" : "Añadir un gato"} onClose={onClose}><form className="form-grid" onSubmit={submit}><div className="cat-photo-picker full-field">{photo ? <img src={photo} alt="Vista previa del gato"/> : <span><Camera /><b>Sin foto</b></span>}<div><label className="photo-select"><Camera />{photo ? "Cambiar foto" : "Seleccionar imagen"}<input type="file" accept="image/jpeg,image/png,image/webp" onChange={event => choosePhoto(event.target.files?.[0])}/></label>{photo && <button type="button" onClick={() => setPhoto("")}><Trash2 />Eliminar foto</button>}<small>JPG, PNG o WebP. Se optimiza antes de guardar.</small>{photoError && <p className="form-error">{photoError}</p>}</div></div><label>Nombre<input name="name" required defaultValue={initial?.name}/></label><label>Fecha de nacimiento<input name="birthDate" type="date" max={new Date().toISOString().slice(0, 10)} defaultValue={initial?.birthDate}/></label><label>Sexo<select name="sex" defaultValue={initial?.sex}><option>Hembra</option><option>Macho</option></select></label><label>Raza<input name="breed" required defaultValue={initial?.breed}/></label><label>Peso (kg)<input name="weight" type="number" step="0.1" min="0" defaultValue={initial?.weight}/></label><label>Fecha del peso<input name="weightDate" type="date" max={new Date().toISOString().slice(0, 10)} defaultValue={initial?.weightDate}/></label><label>Tipo de vida<select name="lifestyle" defaultValue={initial?.lifestyle || "Interior"}><option>Interior</option><option>Exterior</option></select></label><label>Personalidad (opcional)<input name="personality" defaultValue={initial?.personality}/></label><label>Veterinaria habitual<input name="regularVet" defaultValue={initial?.regularVet}/></label><label>Observaciones del dueño<input name="ownerNotes" defaultValue={initial?.ownerNotes}/></label><label className="full-field">Alimentos favoritos<input name="food" defaultValue={initial?.food.join(", ")} placeholder="Pollo, salmón"/></label><label className="full-field">Arenas favoritas<input name="litter" defaultValue={initial?.litter.join(", ")}/></label><label className="full-field">Juguetes favoritos<input name="toys" defaultValue={initial?.toys.join(", ")}/></label><label className="check-label full-field"><input name="sterilized" type="checkbox" defaultChecked={initial?.sterilized}/> Esterilizado</label><button className="primary full-field">Guardar perfil</button></form></FormShell>;
}
function ReminderEditor({ cats, onClose, onSave }: {
    cats: CatProfile[];
    onClose: () => void;
    onSave: (r: Reminder) => void;
}) { function submit(e: FormEvent<HTMLFormElement>) { e.preventDefault(); const f = new FormData(e.currentTarget); onSave({ id: crypto.randomUUID(), catId: String(f.get("catId")), type: String(f.get("type")) as Reminder["type"], date: String(f.get("date")), description: String(f.get("description")), completed: false }); } return <FormShell title="Nuevo recordatorio" onClose={onClose}><form className="stack-form" onSubmit={submit}><label>Gato<select name="catId" required>{cats.map(c => <option value={c.id} key={c.id}>{c.name}</option>)}</select></label><label>Tipo<select name="type"><option>Vacuna</option><option>Desparasitación</option><option>Control veterinario</option><option>Otro</option></select></label><label>Fecha<input name="date" type="date" required/></label><label>Descripción<input name="description" required placeholder="Ej. Control anual"/></label><button className="primary full">Crear recordatorio</button></form></FormShell>; }
function ReviewEditor({ initial, onClose, onSave }: {
    initial: UserReview | null;
    onClose: () => void;
    onSave: (r: UserReview) => void;
}) {
    const [error, setError] = useState(""); const [photos, setPhotos] = useState<string[]>(initial?.photos || []);
    async function addPhotos(files: FileList | null) {
        if (!files) return; const selected = Array.from(files).slice(0, 5 - photos.length);
        const encoded = await Promise.all(selected.map(file => new Promise<string>((resolve, reject) => { const reader = new FileReader(); reader.onload = () => resolve(String(reader.result)); reader.onerror = reject; reader.readAsDataURL(file); })));
        setPhotos([...photos, ...encoded]);
    }
    function submit(e: FormEvent<HTMLFormElement>) {
        e.preventDefault(); const f = new FormData(e.currentTarget), comment = String(f.get("comment")), problem = validateCommunityContent(comment); if (problem) { setError(problem); return; }
        const now = new Date().toISOString(); onSave({ id: initial?.id || crypto.randomUUID(), placeId: initial?.placeId || 0, rating: Number(f.get("rating")), comment, status: reviewNeedsModeration(comment) ? "En revisión" : initial?.status || "Publicada", createdAt: initial?.createdAt || now, updatedAt: initial ? now : undefined, helpful: initial?.helpful || 0, unhelpful: initial?.unhelpful || 0, reported: initial?.reported || false, photos, businessResponse: initial?.businessResponse });
    }
    return <FormShell title={initial ? "Editar reseña" : "Comparte tu experiencia"} onClose={onClose}><Disclaimer /><form className="stack-form" onSubmit={submit}><label>Calificación<select name="rating" defaultValue={initial?.rating || 5}><option value="5">5 · Excelente</option><option value="4">4 · Muy buena</option><option value="3">3 · Buena</option><option value="2">2 · Regular</option><option value="1">1 · Mala</option></select></label><label>Comentario<textarea name="comment" required defaultValue={initial?.comment} placeholder="Describe tu experiencia con respeto y sin datos personales."/></label><label>Fotografías (máximo 5)<input type="file" accept="image/jpeg,image/png,image/webp" multiple disabled={photos.length >= 5} onChange={e => void addPhotos(e.target.files)}/></label>{photos.length > 0 && <div className="review-photo-editor">{photos.map((photo, index) => <span key={index} style={{ backgroundImage: `url(${photo})` }}><button type="button" onClick={() => setPhotos(photos.filter((_, i) => i !== index))}><X /></button></span>)}</div>}<small className="form-hint">Los videos estarán disponibles en una versión futura.</small>{error && <p className="form-error">{error}</p>}<button className="primary full">{reviewNeedsModeration(String(initial?.comment || "")) ? "Guardar para revisión" : "Publicar reseña"}</button></form></FormShell>;
}
function CompareModal({ ids, onClose }: {
    ids: number[];
    onClose: () => void;
}) { return <FormShell title="Comparador de productos" onClose={onClose}><div className="comparison-table"><div><b>Producto</b><b>Precio</b><b>Puntuación</b><b>Reseñas</b></div>{ids.map(id => { const p = places.find(x => x.id === id)!; return <div key={id}><strong>{p.name}</strong><span>{p.price}</span><Stars rating={p.rating}/><span>{p.reviews}</span></div>; })}</div></FormShell>; }
function DetailModal({ place, saved, ownReviews, onClose, onSave, onContact, onNewReview, onEdit, onDelete, onReact, onReport, onBusinessResponse }: {
    place: Place;
    saved: boolean;
    ownReviews: UserReview[];
    onClose: () => void;
    onSave: () => void;
    onContact: () => void;
    onNewReview: () => void;
    onEdit: (r: UserReview) => void;
    onDelete: (id: string) => void;
    onReact: (id: string, key: "helpful" | "unhelpful") => void;
    onReport: (id: string) => void;
    onBusinessResponse: (id: string, response: string) => void;
}) { return <div className="modal-backdrop" onMouseDown={e => e.target === e.currentTarget && onClose()}><div className="detail-modal"><button className="close" onClick={onClose}><X /></button><div className="detail-photo" style={{ backgroundImage: `url(${place.image})` }}/><div className="detail-body"><span className="kicker">{place.category} · {place.district}</span><h2>{place.name}</h2><div className="detail-rating"><Stars rating={place.rating}/><span>{place.reviews + ownReviews.length} reseñas</span>{place.open && <span className="open">Abierto ahora</span>}</div><p>Información de la ficha: dirección en {place.district}, atención y horarios sujetos a confirmación con el negocio.</p>{place.category === "Veterinaria" && <div className="service-icons">{["24 horas", "Hospitalización", "Laboratorio", "Ecografía", "Cirugía", "Atención felina"].map(x => <span key={x}><Check />{x}</span>)}</div>}<div className="detail-actions"><button className="primary" onClick={onSave}><Bookmark />{saved ? "Siguiendo" : "Seguir"}</button><button onClick={onContact}><MessageCircle />Contacto privado</button></div><Disclaimer /><div className="review-title"><h3>Lo que dice la comunidad</h3><button onClick={onNewReview}>Escribir reseña</button></div>{ownReviews.map(r => <div className="review own" key={r.id}><span className="review-avatar">TÚ</span><div><div className="review-head"><b>Tu reseña · {r.status}</b><Stars rating={r.rating}/></div><small>{new Date(r.createdAt).toLocaleDateString("es-PE")} · Nivel Activo</small><p>{r.comment}</p>{r.photos?.length > 0 && <div className="review-photos">{r.photos.map((photo, index) => <img key={index} src={photo} alt={`Foto ${index + 1} de la rese?a`} />)}</div>}{r.updatedAt && <small>Editada el {new Date(r.updatedAt).toLocaleDateString("es-PE")}</small>}{r.businessResponse && <div className="business-response"><b>Respuesta del negocio</b><p>{r.businessResponse}</p></div>}<div className="review-actions"><button onClick={() => onReact(r.id, "helpful")}>Útil ({r.helpful})</button><button onClick={() => onReact(r.id, "unhelpful")}>No útil ({r.unhelpful})</button><button onClick={() => onReport(r.id)} disabled={r.reported}>{r.reported ? "Reportada" : "Reportar"}</button><button onClick={() => onEdit(r)}>Editar</button><button onClick={() => confirm("¿Eliminar esta reseña?") && onDelete(r.id)}>Eliminar</button></div></div></div>)}{reviews.map(r => <div className="review" key={r.user}><span className="review-avatar">{r.avatar}</span><div><div className="review-head"><b>{r.user}</b><Stars rating={r.rating}/></div><small>{r.cat} · Nivel {r.level}</small><p>{r.text}</p><span>{r.date} · Útil ({r.helpful})</span></div></div>)}{place.category !== "Producto" && <BusinessDashboard reviews={ownReviews} onRespond={onBusinessResponse} />}<SafetyNotice /></div></div></div>; }
